-- ======================================== -- v2.0 用户邮箱白名单功能数据库更新 -- 执行此脚本添加新表支持个人/系统双模式 -- 兼容 MySQL 5.7 -- ======================================== SET NAMES utf8mb4; SET FOREIGN_KEY_CHECKS = 0; -- ======================================== -- 1. 配额配置表 -- ======================================== CREATE TABLE IF NOT EXISTS `email_quota_config` ( `id` INT AUTO_INCREMENT PRIMARY KEY, `name` VARCHAR(50) NOT NULL COMMENT '配置名称: free/basic/premium', `daily_limit` INT DEFAULT 100 COMMENT '每日发送限制', `description` VARCHAR(255) DEFAULT NULL COMMENT '配置描述', `is_default` TINYINT(1) DEFAULT 0 COMMENT '是否默认配置', `price_monthly` INT DEFAULT NULL COMMENT '月付价格(分)', `price_yearly` INT DEFAULT NULL COMMENT '年付价格(分)', `created_at` DATETIME DEFAULT CURRENT_TIMESTAMP, INDEX `idx_quota_is_default` (`is_default`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='配额配置模板 - 支持差异化配额'; -- ======================================== -- 2. 用户发件邮箱绑定表（核心） -- ======================================== CREATE TABLE IF NOT EXISTS `user_sender_binding` ( `id` INT AUTO_INCREMENT PRIMARY KEY, `user_id` INT NOT NULL COMMENT '所属用户ID', `email` VARCHAR(120) NOT NULL COMMENT '实际发件地址', `email_type` VARCHAR(20) DEFAULT 'personal' COMMENT '邮箱类型: personal/system', `ses_identity_status` VARCHAR(20) DEFAULT 'pending' COMMENT 'SES验证状态: pending/verified/failed', `ses_verified_at` DATETIME DEFAULT NULL COMMENT 'SES验证通过时间', `verification_token` VARCHAR(6) DEFAULT NULL COMMENT '6位验证码', `token_expires_at` DATETIME DEFAULT NULL COMMENT '验证码过期时间', `real_email` VARCHAR(120) DEFAULT NULL COMMENT '用户真实邮箱(用于Reply-To)', `quota_config_id` INT DEFAULT NULL COMMENT '关联的配额配置ID', `custom_daily_limit` INT DEFAULT NULL COMMENT '个性化每日配额', `daily_sent` INT DEFAULT 0 COMMENT '今日已发送数量', `daily_reset_at` DATETIME DEFAULT NULL COMMENT '配额重置时间', `is_default` TINYINT(1) DEFAULT 0 COMMENT '是否默认发件邮箱', `is_active` TINYINT(1) DEFAULT 1 COMMENT '是否启用', `created_at` DATETIME DEFAULT CURRENT_TIMESTAMP, `updated_at` DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, INDEX `idx_usb_user_id` (`user_id`), INDEX `idx_usb_email` (`email`), INDEX `idx_usb_email_type` (`email_type`), INDEX `idx_usb_is_active` (`is_active`, `is_default`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='用户发件邮箱绑定 - 白名单核心表'; -- ======================================== -- 3. 用户订阅记录表（预留 - 购买升级功能） -- ======================================== CREATE TABLE IF NOT EXISTS `user_subscription` ( `id` INT AUTO_INCREMENT PRIMARY KEY, `user_id` INT NOT NULL COMMENT '用户ID', `quota_config_id` INT NOT NULL COMMENT '购买的配额配置ID', `payment_provider` VARCHAR(20) DEFAULT NULL COMMENT '支付服务商: alipay/wechat/stripe', `payment_order_id` VARCHAR(100) DEFAULT NULL COMMENT '支付服务商订单号', `amount_paid` INT DEFAULT NULL COMMENT '实际支付金额(分)', `status` VARCHAR(20) DEFAULT 'pending' COMMENT '状态: pending/paid/cancelled/expired', `started_at` DATETIME DEFAULT NULL COMMENT '订阅开始时间', `expires_at` DATETIME DEFAULT NULL COMMENT '订阅过期时间', `created_at` DATETIME DEFAULT CURRENT_TIMESTAMP, INDEX `idx_sub_user_id` (`user_id`), INDEX `idx_sub_status` (`status`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='用户订阅/购买记录（预留 - 购买升级功能）'; -- ======================================== -- 4. 系统通知表 -- ======================================== CREATE TABLE IF NOT EXISTS `notification` ( `id` INT AUTO_INCREMENT PRIMARY KEY, `user_id` INT NOT NULL COMMENT '用户ID', `type` VARCHAR(50) NOT NULL COMMENT '通知类型: email_reply/quota_warning/etc', `title` VARCHAR(200) NOT NULL COMMENT '通知标题', `content` TEXT DEFAULT NULL COMMENT '通知内容', `is_read` TINYINT(1) DEFAULT 0 COMMENT '是否已读', `related_data` JSON DEFAULT NULL COMMENT '关联数据JSON', `created_at` DATETIME DEFAULT CURRENT_TIMESTAMP, `read_at` DATETIME DEFAULT NULL COMMENT '阅读时间', INDEX `idx_notif_user_id` (`user_id`), INDEX `idx_notif_type` (`type`), INDEX `idx_notif_created_at` (`created_at`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='系统通知 - 用于回复通知、系统消息等'; -- ======================================== -- 5. EmailLog 表增强 (兼容 MySQL 5.7) -- ======================================== -- MySQL 5.7 不支持 ADD COLUMN IF NOT EXISTS，使用存储过程检查 DELIMITER // CREATE PROCEDURE IF NOT EXISTS AddEmailLogColumns() BEGIN IF NOT EXISTS ( SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'email_log' AND TABLE_SCHEMA = DATABASE() AND COLUMN_NAME = 'sender_binding_id' ) THEN ALTER TABLE `email_log` ADD COLUMN `sender_binding_id` INT DEFAULT NULL COMMENT '关联user_sender_binding.id'; END IF; IF NOT EXISTS ( SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'email_log' AND TABLE_SCHEMA = DATABASE() AND COLUMN_NAME = 'sender_email_type' ) THEN ALTER TABLE `email_log` ADD COLUMN `sender_email_type` VARCHAR(20) DEFAULT NULL COMMENT '发件类型: personal/system/system_default'; END IF; IF NOT EXISTS ( SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'email_log' AND TABLE_SCHEMA = DATABASE() AND COLUMN_NAME = 'reply_to_email' ) THEN ALTER TABLE `email_log` ADD COLUMN `reply_to_email` VARCHAR(120) DEFAULT NULL COMMENT 'Reply-To地址'; END IF; -- 检查索引是否存在 IF NOT EXISTS ( SELECT 1 FROM INFORMATION_SCHEMA.STATISTICS WHERE TABLE_NAME = 'email_log' AND INDEX_NAME = 'idx_emaillog_sender_binding_id' AND TABLE_SCHEMA = DATABASE() ) THEN ALTER TABLE `email_log` ADD INDEX `idx_emaillog_sender_binding_id` (`sender_binding_id`); END IF; END // DELIMITER ; CALL AddEmailLogColumns(); DROP PROCEDURE AddEmailLogColumns; -- ======================================== -- 6. 插入默认配额配置 (兼容 MySQL 5.7) -- ======================================== INSERT INTO `email_quota_config` (`name`, `daily_limit`, `description`, `is_default`, `price_monthly`, `price_yearly`) SELECT * FROM (SELECT 'free' AS `name`, 100 AS `daily_limit`, 'Free tier: 100 emails per day' AS `description`, 1 AS `is_default`, NULL AS `price_monthly`, NULL AS `price_yearly`) AS tmp WHERE NOT EXISTS ( SELECT 1 FROM `email_quota_config` WHERE `name` = 'free' ) LIMIT 1; INSERT INTO `email_quota_config` (`name`, `daily_limit`, `description`, `is_default`, `price_monthly`, `price_yearly`) SELECT * FROM (SELECT 'basic' AS `name`, 500 AS `daily_limit`, 'Basic tier: 500 emails per day' AS `description`, 0 AS `is_default`, NULL AS `price_monthly`, NULL AS `price_yearly`) AS tmp WHERE NOT EXISTS ( SELECT 1 FROM `email_quota_config` WHERE `name` = 'basic' ) LIMIT 1; INSERT INTO `email_quota_config` (`name`, `daily_limit`, `description`, `is_default`, `price_monthly`, `price_yearly`) SELECT * FROM (SELECT 'premium' AS `name`, 2000 AS `daily_limit`, 'Premium tier: 2000 emails per day' AS `description`, 0 AS `is_default`, NULL AS `price_monthly`, NULL AS `price_yearly`) AS tmp WHERE NOT EXISTS ( SELECT 1 FROM `email_quota_config` WHERE `name` = 'premium' ) LIMIT 1; SET FOREIGN_KEY_CHECKS = 1; -- ======================================== -- 完成 -- ======================================== SELECT 'v2.0 Schema update completed successfully!' AS status; 